@pytest.mark.asyncio
async def test_streaming_text_response(client):
    """Streaming request with no tools returns text-only SSE events."""
    CONFIG.tool_calls_per_turn = 0

    resp = await client.post(
        "/v1/messages",
        json={
            "model": "claude-sonnet-4-5-20250929",
            "messages": [{"role": "user", "content": "Hello"}],
            "max_tokens": 100,
            "stream": True,
        },
    )
    assert resp.status_code == 200

    events = _parse_sse(resp.text)

    # Check event flow: message_start → content_block_start → deltas → stop → message_delta → message_stop
    event_types = [e["type"] for e in events if e.get("type") != "ping"]
    assert event_types[0] == "message_start"
    assert "content_block_start" in event_types
    assert "content_block_delta" in event_types
    assert "content_block_stop" in event_types
    assert event_types[-2] == "message_delta"
    assert event_types[-1] == "message_stop"

    # Check stop_reason is end_turn
    message_delta = next(e for e in events if e.get("type") == "message_delta")
    assert message_delta["delta"]["stop_reason"] == "end_turn"


@pytest.mark.asyncio
async def test_streaming_tool_use_response(client):
    """First request with tools triggers a tool_use response."""
    CONFIG.tool_calls_per_turn = 1

    resp = await client.post(
        "/v1/messages",
        json={
            "model": "claude-sonnet-4-5-20250929",
            "messages": [{"role": "user", "content": "What is Genesis 1:1?"}],
            "max_tokens": 1000,
            "stream": True,
            "tools": [{"name": "mcp__sefaria__get_text", "description": "Get text"}],
        },
    )
    assert resp.status_code == 200

    events = _parse_sse(resp.text)

    # Should have a tool_use content block
    tool_blocks = [
        e
        for e in events
        if e.get("type") == "content_block_start"
        and e.get("content_block", {}).get("type") == "tool_use"
    ]
    assert len(tool_blocks) == 1

    # Should have input_json_delta events
    json_deltas = [
        e
        for e in events
        if e.get("type") == "content_block_delta"
        and e.get("delta", {}).get("type") == "input_json_delta"
    ]
    assert len(json_deltas) > 0

    # Accumulated JSON should be valid
    partial_json = "".join(d["delta"]["partial_json"] for d in json_deltas)
    parsed = json.loads(partial_json)
    assert isinstance(parsed, dict)

    # Stop reason should be tool_use
    message_delta = next(e for e in events if e.get("type") == "message_delta")
    assert message_delta["delta"]["stop_reason"] == "tool_use"


