@pytest.mark.asyncio
async def test_multiple_tool_rounds(client):
    """Mock supports configurable number of tool-calling rounds."""
    CONFIG.tool_calls_per_turn = 2
    tools = [{"name": "mcp__sefaria__get_text", "description": "Get text"}]

    def _stop_reason(resp_text: str) -> str:
        events = _parse_sse(resp_text)
        md = next(e for e in events if e.get("type") == "message_delta")
        return md["delta"]["stop_reason"]

    # Round 0: no tool results yet → should return tool_use
    resp = await client.post(
        "/v1/messages",
        json={
            "model": "claude-sonnet-4-5-20250929",
            "messages": [{"role": "user", "content": "Research this topic"}],
            "max_tokens": 1000,
            "stream": True,
            "tools": tools,
        },
    )
    assert _stop_reason(resp.text) == "tool_use"

    # Round 1: 1 tool result → still should return tool_use (need 2 total)
    resp = await client.post(
        "/v1/messages",
        json={
            "model": "claude-sonnet-4-5-20250929",
            "messages": [
                {"role": "user", "content": "Research this topic"},
                {
                    "role": "assistant",
                    "content": [
                        {"type": "tool_use", "id": "t1", "name": "get_text", "input": {}},
                    ],
                },
                {
                    "role": "user",
                    "content": [{"type": "tool_result", "tool_use_id": "t1", "content": "..."}],
                },
            ],
            "max_tokens": 1000,
            "stream": True,
            "tools": tools,
        },
    )
    assert _stop_reason(resp.text) == "tool_use"

    # Round 2: 2 tool results → should return end_turn (limit reached)
    resp = await client.post(
        "/v1/messages",
        json={
            "model": "claude-sonnet-4-5-20250929",
            "messages": [
                {"role": "user", "content": "Research this topic"},
                {
                    "role": "assistant",
                    "content": [
                        {"type": "tool_use", "id": "t1", "name": "get_text", "input": {}},
                    ],
                },
                {
                    "role": "user",
                    "content": [{"type": "tool_result", "tool_use_id": "t1", "content": "..."}],
                },
                {
                    "role": "assistant",
                    "content": [
                        {"type": "tool_use", "id": "t2", "name": "get_text", "input": {}},
                    ],
                },
                {
                    "role": "user",
                    "content": [{"type": "tool_result", "tool_use_id": "t2", "content": "..."}],
                },
            ],
            "max_tokens": 1000,
            "stream": True,
            "tools": tools,
        },
    )
    assert _stop_reason(resp.text) == "end_turn"


# ---------------------------------------------------------------------------
# SSE parser helper
# ---------------------------------------------------------------------------


def _parse_sse(text: str) -> list[dict]:
    """Parse SSE text into a list of data dicts."""
    events = []
    for line in text.strip().split("\n"):
        if line.startswith("data: "):
            events.append(json.loads(line[6:]))  # Let JSONDecodeError propagate
    return events
